import { useState, useEffect, useCallback } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  KeyboardAvoidingView,
  Platform,
  Alert,
  ActivityIndicator,
} from 'react-native';
import { useRouter } from 'expo-router';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useSocket } from '../src/hooks/useSocket';
import { useAppStore } from '../src/store/useAppStore';
import { getSocket } from '../src/services/socket';
import { colors, spacing, fontSize, borderRadius } from '../src/theme';

const NICKNAME_KEY = '@basra/nickname';

export default function HomeScreen() {
  const router = useRouter();
  const { createRoom, joinRoom } = useSocket();
  const { nickname, setNickname, setIsHost, setRoomCode, roomCode, targetScore } = useAppStore();

  const [joinCode, setJoinCode] = useState('');
  const [showJoin, setShowJoin] = useState(false);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    AsyncStorage.getItem(NICKNAME_KEY).then((saved) => {
      if (saved) setNickname(saved);
    });
  }, []);

  const saveNickname = (name: string) => {
    setNickname(name);
    AsyncStorage.setItem(NICKNAME_KEY, name);
  };

  const handleCreate = useCallback(() => {
    if (!nickname.trim()) {
      Alert.alert('Enter a nickname', 'Please enter your name first.');
      return;
    }
    setLoading(true);
    setIsHost(true);

    const socket = getSocket();

    const onRoomCreated = () => {
      cleanup();
      router.push('/lobby');
    };
    const onError = (data: { message: string }) => {
      cleanup();
      Alert.alert('Error', data.message);
    };
    const cleanup = () => {
      setLoading(false);
      socket.off('room-created', onRoomCreated);
      socket.off('error', onError);
    };

    socket.on('room-created', onRoomCreated);
    socket.on('error', onError);

    createRoom(nickname.trim(), targetScore);
  }, [nickname, targetScore, createRoom, setIsHost, router]);

  const handleJoin = useCallback(() => {
    if (!nickname.trim()) {
      Alert.alert('Enter a nickname', 'Please enter your name first.');
      return;
    }
    if (!joinCode.trim()) {
      Alert.alert('Enter room code', 'Please enter a room code to join.');
      return;
    }
    setLoading(true);
    setIsHost(false);

    const socket = getSocket();

    const onRoomJoined = () => {
      cleanup();
      router.push('/lobby');
    };
    const onError = (data: { message: string }) => {
      cleanup();
      Alert.alert('Error', data.message);
    };
    const cleanup = () => {
      setLoading(false);
      socket.off('room-joined', onRoomJoined);
      socket.off('error', onError);
    };

    socket.on('room-joined', onRoomJoined);
    socket.on('error', onError);

    joinRoom(joinCode.trim().toUpperCase(), nickname.trim());
  }, [nickname, joinCode, joinRoom, setIsHost, router]);

  return (
    <KeyboardAvoidingView
      style={styles.container}
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
    >
      <View style={styles.content}>
