  2→import { View, StyleSheet, SafeAreaView, Text } from 'react-native';
  3→import { useRouter } from 'expo-router';
  4→import { Card as CardType } from '@basra/shared';
  5→import { useSocket } from '../src/hooks/useSocket';
  6→import { useGameStore } from '../src/store/useGameStore';
  7→import { useAppStore } from '../src/store/useAppStore';
  8→import { lightTap, mediumTap, successVibration } from '../src/utils/haptics';
  9→import Card from '../src/components/Card';
 10→import CardHand from '../src/components/CardHand';
 11→import TableArea from '../src/components/TableArea';
 12→import OpponentHand from '../src/components/OpponentHand';
 13→import ScoreBar from '../src/components/ScoreBar';
 14→import DeckPile from '../src/components/DeckPile';
 15→import BasraToast from '../src/components/BasraToast';
 16→import TurnIndicator from '../src/components/TurnIndicator';
 17→import { colors, spacing, fontSize } from '../src/theme';
 18→
 19→export default function GameScreen() {
 20→  const router = useRouter();
 21→  const { playCard: emitPlayCard } = useSocket();
 22→  const {
 23→    hand,
 24→    table,
 25→    deckRemaining,
 26→    currentTurn,
 27→    myId,
 28→    opponentCardCount,
 29→    roundNumber,
 30→    targetScore,
 31→    players,
 32→    lastPlay,
 33→    phase,
 34→    opponentConnected,
 35→  } = useGameStore();
 36→
 37→  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);
 38→  const [showBasra, setShowBasra] = useState(false);
 39→  const [isJackBasra, setIsJackBasra] = useState(false);
 40→
 41→  const isMyTurn = currentTurn === myId;
 42→  const me = players.find((p) => p.id === myId);
 43→  const opponent = players.find((p) => p.id !== myId);
 44→
 45→  // Navigate to score screen on round end or game over
 46→  useEffect(() => {
 47→    if (phase === 'round-end' || phase === 'game-over') {
 48→      router.push('/score');
 49→    }
 50→  }, [phase]);
 51→
 52→  // Show basra toast when a basra occurs
 53→  useEffect(() => {
 54→    if (lastPlay && (lastPlay.isBasra || lastPlay.isJackBasra)) {
 55→      setIsJackBasra(lastPlay.isJackBasra);
 56→      setShowBasra(true);
 57→    }
 58→  }, [lastPlay]);
 59→
 60→  // Haptic feedback on capture
 61→  useEffect(() => {
 62→    if (lastPlay && lastPlay.capturedCards.length > 0) {
 63→      if (lastPlay.isBasra || lastPlay.isJackBasra) {
 64→        successVibration();
 65→      } else {
 66→        mediumTap();
 67→      }
 68→    }
 69→  }, [lastPlay]);
 70→
 71→  const handleCardPress = useCallback(
 72→    (card: CardType) => {
 73→      if (!isMyTurn) return;
 74→
 75→      if (selectedCardId === card.id) {
 76→        // Double tap / confirm: play the card
 77→        lightTap();
 78→        emitPlayCard(card.id);
 79→        setSelectedCardId(null);
 80→      } else {
 81→        // Select the card
 82→        lightTap();
 83→        setSelectedCardId(card.id);
 84→      }
 85→    },
 86→    [isMyTurn, selectedCardId, emitPlayCard]
 87→  );
 88→
 89→  if (!me || !opponent) {
 90→    return (
 91→      <View style={styles.container}>
 92→        <Text style={styles.loadingText}>Loading...</Text>
 93→      </View>
 94→    );
 95→  }
 96→
 97→  return (
 98→    <SafeAreaView style={styles.container}>
 99→      {/* Score Bar */}
100→      <ScoreBar
101→        myScore={me.score}
102→        opponentScore={opponent.score}
103→        myName={me.nickname}
104→        opponentName={opponent.nickname}
105→        targetScore={targetScore}
106→        roundNumber={roundNumber}
107→        deckRemaining={deckRemaining}
108→      />
109→
110→      {/* Opponent Hand */}
111→      <OpponentHand
112→        cardCount={opponentCardCount}
113→        nickname={opponent.nickname}
114→        score={opponent.score}
115→        capturedCount={opponent.capturedCount}
116→      />
117→
118→      {/* Disconnection Warning */}
119→      {!opponentConnected && (
120→        <View style={styles.disconnectBanner}>
121→          <Text style={styles.disconnectText}>Opponent disconnected...</Text>
122→        </View>
123→      )}
124→
125→      {/* Turn Indicator */}
126→      <TurnIndicator isMyTurn={isMyTurn} />
127→
128→      {/* Table */}
129→      <TableArea cards={table} />
130→
131→      {/* My capture pile info */}
132→      <DeckPile
133→        myCapturedCount={me.capturedCount}
134→        myBasras={me.basras}
135→        myJackBasras={me.jackBasras}
136→      />
137→
138→      {/* My Hand */}
139→      <View style={styles.handSection}>
140→        <CardHand
141→          cards={hand}
142→          onCardPress={handleCardPress}
143→          selectedCardId={selectedCardId}
144→          disabled={!isMyTurn}
145→        />
146→        {selectedCardId && isMyTurn && (
147→          <Text style={styles.hint}>Tap again to play</Text>
148→        )}
149→      </View>
150→
151→      {/* Basra Toast */}
152→      <BasraToast
153→        visible={showBasra}
154→        isJackBasra={isJackBasra}
155→        onHide={() => setShowBasra(false)}
156→      />
157→    </SafeAreaView>
158→  );
159→}
