  1→import { TouchableOpacity, View, Text, StyleSheet } from 'react-native';
  2→import Animated, {
  3→  useAnimatedStyle,
  4→  useSharedValue,
  5→  withSpring,
  6→  withTiming,
  7→} from 'react-native-reanimated';
  8→import { Card as CardType } from '@basra/shared';
  9→import { getSuitSymbol, getSuitColor, getDisplayRank } from '../utils/cardImages';
 10→import { colors, cardDimensions } from '../theme';
 11→
 12→interface CardProps {
 13→  card: CardType;
 14→  faceUp?: boolean;
 15→  onPress?: (card: CardType) => void;
 16→  selected?: boolean;
 17→  disabled?: boolean;
 18→  small?: boolean;
 19→}
 20→
 21→const AnimatedTouchable = Animated.createAnimatedComponent(TouchableOpacity);
 22→
 23→export default function Card({
 24→  card,
 25→  faceUp = true,
 26→  onPress,
 27→  selected = false,
 28→  disabled = false,
 29→  small = false,
 30→}: CardProps) {
 31→  const scale = useSharedValue(1);
 32→
 33→  const suitColor = getSuitColor(card.suit);
 34→  const suitSymbol = getSuitSymbol(card.suit);
 35→  const displayRank = getDisplayRank(card.rank);
 36→
 37→  const w = small ? cardDimensions.width * 0.7 : cardDimensions.width;
 38→  const h = small ? cardDimensions.height * 0.7 : cardDimensions.height;
 39→
 40→  const animatedStyle = useAnimatedStyle(() => ({
 41→    transform: [
 42→      { scale: scale.value },
 43→      { translateY: selected ? -10 : 0 },
 44→    ],
 45→  }));
 46→
 47→  const handlePressIn = () => {
 48→    scale.value = withSpring(0.95);
 49→  };
 50→
 51→  const handlePressOut = () => {
 52→    scale.value = withSpring(1);
 53→  };
 54→
 55→  const handlePress = () => {
 56→    if (!disabled && onPress) {
 57→      onPress(card);
 58→    }
 59→  };
 60→
 61→  if (!faceUp) {
 62→    return (
 63→      <View style={[styles.card, styles.cardBack, { width: w, height: h }]}>
 64→        <View style={styles.backPattern}>
 65→          <Text style={styles.backText}>B</Text>
 66→        </View>
 67→      </View>
 68→    );
 69→  }
 70→
 71→  return (
 72→    <AnimatedTouchable
 73→      style={[
 74→        styles.card,
 75→        { width: w, height: h },
 76→        selected && styles.cardSelected,
 77→        disabled && styles.cardDisabled,
 78→        animatedStyle,
 79→      ]}
 80→      onPress={handlePress}
 81→      onPressIn={handlePressIn}
 82→      onPressOut={handlePressOut}
 83→      activeOpacity={0.8}
 84→      disabled={disabled}
 85→    >
 86→      <Text style={[styles.rankTop, { color: suitColor }]}>
 87→        {displayRank}
 88→      </Text>
 89→      <Text style={[styles.suitCenter, { color: suitColor, fontSize: small ? 18 : 24 }]}>
 90→        {suitSymbol}
 91→      </Text>
 92→      <Text style={[styles.rankBottom, { color: suitColor }]}>
 93→        {displayRank}
 94→      </Text>
 95→    </AnimatedTouchable>
 96→  );
 97→}
 98→
