100→  card: {
101→    backgroundColor: '#fff',
102→    borderRadius: cardDimensions.borderRadius,
103→    borderWidth: 1,
104→    borderColor: '#ddd',
105→    alignItems: 'center',
106→    justifyContent: 'center',
107→    padding: 2,
108→    shadowColor: '#000',
109→    shadowOffset: { width: 0, height: 2 },
110→    shadowOpacity: 0.2,
111→    shadowRadius: 3,
112→    elevation: 4,
113→  },
114→  cardBack: {
115→    backgroundColor: colors.cardBack,
116→    borderColor: colors.cardBorder,
117→  },
118→  backPattern: {
