 58→export const useGameStore = create<GameStore>((set, get) => ({
 59→  phase: 'waiting',
 60→  hand: [],
 61→  table: [],
 62→  deckRemaining: 0,
 63→  currentTurn: null,
 64→  dealer: null,
 65→  myId: null,
 66→  opponentCardCount: 0,
 67→  roundNumber: 0,
 68→  targetScore: 121,
 69→  players: [],
 70→  lastPlay: null,
 71→  roundEndData: null,
 72→  gameOverData: null,
 73→  opponentConnected: true,
 74→
 75→  setMyId: (id) => set({ myId: id }),
 76→
 77→  onGameStart: (data, myId) =>
 78→    set({
 79→      phase: 'playing',
 80→      hand: data.hand,
 81→      table: data.tableCards,
 82→      deckRemaining: data.deckRemaining,
 83→      currentTurn: data.currentTurn,
 84→      dealer: data.dealer,
 85→      myId,
 86→      opponentCardCount: data.opponentCardCount,
 87→      roundNumber: data.roundNumber,
 88→      targetScore: data.targetScore,
 89→      players: data.players.map((p) => ({
 90→        id: p.id,
 91→        nickname: p.nickname,
 92→        score: p.score,
 93→        capturedCount: 0,
 94→        basras: 0,
 95→        jackBasras: 0,
 96→      })),
 97→      lastPlay: null,
 98→      roundEndData: null,
 99→      gameOverData: null,
100→    }),
101→
102→  onCardsDealt: (data) =>
103→    set({
104→      hand: data.hand,
105→      deckRemaining: data.deckRemaining,
106→      opponentCardCount: data.opponentCardCount,
107→    }),
108→
109→  onCardPlayed: (data) => {
110→    const state = get();
111→    const isMe = data.playerId === state.myId;
112→
113→    set({
114→      table: data.tableAfter,
115→      currentTurn: data.currentTurn,
116→      lastPlay: data,
117→      // If I played, remove the card from my hand
118→      hand: isMe
119→        ? state.hand.filter((c) => c.id !== data.card.id)
120→        : state.hand,
121→      // If opponent played, decrement their count
122→      opponentCardCount: isMe
123→        ? state.opponentCardCount
124→        : state.opponentCardCount - 1,
125→      // Update captured counts
126→      players: state.players.map((p) =>
127→        p.id === data.playerId
128→          ? { ...p, capturedCount: data.playerCapturedCount }
129→          : p
130→      ),
131→    });
132→  },
