  1→import { Server, Socket } from 'socket.io';
  2→import { RoomManager } from '../room-manager';
  3→import {
  4→  CreateRoomPayload,
  5→  JoinRoomPayload,
  6→  RoomCreatedPayload,
  7→  RoomJoinedPayload,
  8→  OpponentJoinedPayload,
  9→} from '@basra/shared';
 10→
 11→export function registerLobbyHandlers(
 12→  io: Server,
 13→  socket: Socket,
 14→  roomManager: RoomManager
 15→): void {
 16→  socket.on('create-room', (data: CreateRoomPayload) => {
 17→    try {
 18→      const room = roomManager.createRoom(socket.id, data.nickname, data.targetScore);
 19→      const playerId = roomManager.getPlayerId(socket.id)!;
 20→
 21→      socket.join(room.code);
 22→
 23→      const response: RoomCreatedPayload = {
 24→        roomCode: room.code,
 25→        playerId,
 26→      };
 27→      socket.emit('room-created', response);
 28→
 29→      console.log(`Room ${room.code} created by ${data.nickname}`);
 30→    } catch (err: any) {
 31→      socket.emit('error', { message: err.message });
 32→    }
 33→  });
 34→
 35→  socket.on('join-room', (data: JoinRoomPayload) => {
 36→    try {
 37→      const code = data.roomCode.toUpperCase().trim();
 38→      const result = roomManager.joinRoom(socket.id, code, data.nickname);
 39→
 40→      if (!result) {
 41→        socket.emit('error', { message: 'Room not found or full' });
 42→        return;
 43→      }
 44→
 45→      const { room, playerId } = result;
 46→      socket.join(room.code);
 47→
 48→      // Tell the joiner about the room
 49→      const host = room.engine.getState().players[0];
 50→      const joinedResponse: RoomJoinedPayload = {
 51→        roomCode: room.code,
 52→        playerId,
 53→        opponentNickname: host.nickname,
 54→      };
 55→      socket.emit('room-joined', joinedResponse);
 56→
 57→      // Tell the host about the joiner
 58→      const hostSocketId = roomManager.getOpponentSocketId(room, playerId);
 59→      if (hostSocketId) {
 60→        const opponentJoined: OpponentJoinedPayload = {
 61→          opponentNickname: data.nickname,
 62→        };
 63→        io.to(hostSocketId).emit('opponent-joined', opponentJoined);
 64→      }
 65→
 66→      console.log(`${data.nickname} joined room ${room.code}`);
 67→    } catch (err: any) {
 68→      socket.emit('error', { message: err.message });
 69→    }
 70→  });
 71→
 72→  socket.on('player-ready', () => {
 73→    try {
 74→      const room = roomManager.getRoomBySocket(socket.id);
 75→      if (!room) {
 76→        socket.emit('error', { message: 'Not in a room' });
 77→        return;
 78→      }
 79→
 80→      if (room.engine.getPlayerCount() < 2) {
 81→        socket.emit('error', { message: 'Waiting for opponent' });
 82→        return;
 83→      }
 84→
 85→      // Start the game
 86→      room.engine.startGame();
 87→      const state = room.engine.getState();
 88→
 89→      // Send each player their own hand and the shared state
 90→      for (const player of state.players) {
 91→        const sid = room.playerSockets.get(player.id);
 92→        if (!sid) continue;
 93→
 94→        const opponent = state.players.find(p => p.id !== player.id)!;
 95→
 96→        io.to(sid).emit('game-start', {
 97→          hand: player.hand,
 98→          tableCards: state.table,
 99→          deckRemaining: state.deckRemaining,
100→          currentTurn: state.currentTurn,
101→          dealer: state.dealer,
102→          opponentCardCount: opponent.hand.length,
103→          roundNumber: state.roundNumber,
104→          targetScore: state.targetScore,
105→          players: state.players.map(p => ({
106→            id: p.id,
107→            nickname: p.nickname,
108→            score: p.score,
109→          })),
110→        });
111→
112→        if (state.currentTurn === player.id) {
113→          io.to(sid).emit('your-turn', {});
114→        }
115→      }
116→
117→      console.log(`Game started in room ${room.code}`);
118→    } catch (err: any) {
119→      socket.emit('error', { message: err.message });
120→    }
121→  });
122→}
