import { create } from 'zustand';
import {
  Card,
  GamePhase,
  CardPlayedPayload,
  GameStartPayload,
  CardsDealtPayload,
  RoundEndPayload,
  GameOverPayload,
} from '@basra/shared';

interface PlayerInfo {
  id: string;
  nickname: string;
  score: number;
  capturedCount: number;
  basras: number;
  jackBasras: number;
}

interface GameStore {
  phase: GamePhase;
  hand: Card[];
  table: Card[];
  deckRemaining: number;
  currentTurn: string | null;
  dealer: string | null;
  myId: string | null;
  opponentCardCount: number;
  roundNumber: number;
  targetScore: number;
  players: PlayerInfo[];

  // Last play animation data
  lastPlay: CardPlayedPayload | null;

  // Round end data
  roundEndData: RoundEndPayload | null;

  // Game over data
  gameOverData: GameOverPayload | null;

  // Whether opponent is connected
  opponentConnected: boolean;

  // Actions
  setMyId: (id: string) => void;
  onGameStart: (data: GameStartPayload, myId: string) => void;
  onCardsDealt: (data: CardsDealtPayload) => void;
  onCardPlayed: (data: CardPlayedPayload) => void;
  onRoundEnd: (data: RoundEndPayload) => void;
  onGameOver: (data: GameOverPayload) => void;
  setOpponentConnected: (connected: boolean) => void;
  isMyTurn: () => boolean;
  reset: () => void;
}

export const useGameStore = create<GameStore>((set, get) => ({
  phase: 'waiting',
  hand: [],
  table: [],
  deckRemaining: 0,
  currentTurn: null,
  dealer: null,
  myId: null,
  opponentCardCount: 0,
  roundNumber: 0,
  targetScore: 121,
  players: [],
  lastPlay: null,
  roundEndData: null,
  gameOverData: null,
  opponentConnected: true,

  setMyId: (id) => set({ myId: id }),

  onGameStart: (data, myId) =>
    set({
      phase: 'playing',
      hand: data.hand,
      table: data.tableCards,
      deckRemaining: data.deckRemaining,
      currentTurn: data.currentTurn,
      dealer: data.dealer,
      myId,
      opponentCardCount: data.opponentCardCount,
      roundNumber: data.roundNumber,
      targetScore: data.targetScore,
      players: data.players.map((p) => ({
        id: p.id,
        nickname: p.nickname,
        score: p.score,
        capturedCount: 0,
        basras: 0,
        jackBasras: 0,
      })),
      lastPlay: null,
      roundEndData: null,
      gameOverData: null,
    }),

  onCardsDealt: (data) =>
    set({
      hand: data.hand,
      deckRemaining: data.deckRemaining,
      opponentCardCount: data.opponentCardCount,
    }),

  onCardPlayed: (data) => {
    const state = get();
    const isMe = data.playerId === state.myId;

    set({
      table: data.tableAfter,
      currentTurn: data.currentTurn,
      lastPlay: data,
      // If I played, remove the card from my hand
      hand: isMe
        ? state.hand.filter((c) => c.id !== data.card.id)
        : state.hand,
      // If opponent played, decrement their count
      opponentCardCount: isMe
        ? state.opponentCardCount
        : state.opponentCardCount - 1,
      // Update captured counts
      players: state.players.map((p) =>
        p.id === data.playerId
          ? { ...p, capturedCount: data.playerCapturedCount }
          : p
      ),
    });
  },

  onRoundEnd: (data) =>
    set({
      phase: 'round-end',
      roundEndData: data,
      players: data.players.map((p) => ({
        id: p.id,
        nickname: p.nickname,
        score: p.totalScore,
        capturedCount: p.capturedCount,
        basras: p.basras,
        jackBasras: p.jackBasras,
      })),
    }),

  onGameOver: (data) =>
    set({
      phase: 'game-over',
      gameOverData: data,
    }),

  setOpponentConnected: (connected) => set({ opponentConnected: connected }),

  isMyTurn: () => {
    const state = get();
    return state.currentTurn === state.myId;
  },

  reset: () =>
    set({
      phase: 'waiting',
      hand: [],
      table: [],
      deckRemaining: 0,
      currentTurn: null,
      dealer: null,
      myId: null,
      opponentCardCount: 0,
      roundNumber: 0,
      players: [],
      lastPlay: null,
      roundEndData: null,
      gameOverData: null,
      opponentConnected: true,
    }),
}));

import { View, Text, TouchableOpacity, StyleSheet, SafeAreaView } from 'react-native';
import { useRouter } from 'expo-router';
import { useSocket } from '../src/hooks/useSocket';
import { useGameStore } from '../src/store/useGameStore';
import { useAppStore } from '../src/store/useAppStore';
import { colors, spacing, fontSize, borderRadius } from '../src/theme';
import { BASRA_POINTS, JACK_BASRA_POINTS, MOST_CARDS_BONUS } from '@basra/shared';

export default function ScoreScreen() {
  const router = useRouter();
  const { nextRound, rematch } = useSocket();
  const { phase, roundEndData, gameOverData, players, myId } = useGameStore();

  const isGameOver = phase === 'game-over';

  const handleNextRound = () => {
    nextRound();
    router.replace('/game');
  };

  const handleRematch = () => {
    rematch();
    router.replace('/game');
  };

  const handleHome = () => {
    useGameStore.getState().reset();
    useAppStore.getState().reset();
    router.replace('/');
  };

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>
        {isGameOver ? 'Game Over!' : `Round ${roundEndData?.roundNumber} Complete`}
      </Text>

      {/* Winner announcement for game over */}
      {isGameOver && gameOverData && (
        <View style={styles.winnerSection}>
          <Text style={styles.winnerLabel}>
            {gameOverData.winnerId === myId ? 'You Win!' : `${gameOverData.winnerNickname} Wins!`}
          </Text>
        </View>
      )}

      {/* Round score breakdown */}
      {roundEndData && (
        <View style={styles.scoresContainer}>
          {roundEndData.players.map((player) => {
            const isMe = player.id === myId;
            return (
              <View key={player.id} style={[styles.playerCard, isMe && styles.myCard]}>
                <Text style={styles.playerName}>
                  {player.nickname} {isMe ? '(You)' : ''}
                </Text>

                <View style={styles.statRow}>
                  <Text style={styles.statLabel}>Cards captured</Text>
                  <Text style={styles.statValue}>{player.capturedCount}</Text>
                </View>

                <View style={styles.statRow}>
                  <Text style={styles.statLabel}>Most cards bonus</Text>
                  <Text style={styles.statValue}>
                    {(() => {
                      const other = roundEndData.players.find(p => p.id !== player.id)!;
                      return player.capturedCount > other.capturedCount ? `+${MOST_CARDS_BONUS}` : '0';
                    })()}
                  </Text>
                </View>

                <View style={styles.statRow}>
                  <Text style={styles.statLabel}>Basras ({player.basras}x)</Text>
                  <Text style={styles.statValue}>+{player.basras * BASRA_POINTS}</Text>
                </View>

                <View style={styles.statRow}>
                  <Text style={styles.statLabel}>Jack Basras ({player.jackBasras}x)</Text>
                  <Text style={styles.statValue}>+{player.jackBasras * JACK_BASRA_POINTS}</Text>
                </View>

                <View style={styles.divider} />

                <View style={styles.statRow}>
                  <Text style={styles.roundTotalLabel}>Round Points</Text>
                  <Text style={styles.roundTotalValue}>+{player.roundPoints}</Text>
                </View>

                <View style={styles.statRow}>
                  <Text style={styles.totalLabel}>Total Score</Text>
                  <Text style={styles.totalValue}>{player.totalScore}</Text>
                </View>
              </View>
            );
          })}
        </View>
      )}

      {/* Action buttons */}
      <View style={styles.actions}>
        {isGameOver ? (
          <>
            <TouchableOpacity style={styles.primaryButton} onPress={handleRematch}>
              <Text style={styles.buttonText}>Rematch</Text>
            </TouchableOpacity>
            <TouchableOpacity style={styles.secondaryButton} onPress={handleHome}>
              <Text style={styles.secondaryButtonText}>Home</Text>
            </TouchableOpacity>
          </>
        ) : (
          <TouchableOpacity style={styles.primaryButton} onPress={handleNextRound}>
            <Text style={styles.buttonText}>Next Round</Text>
          </TouchableOpacity>
        )}
      </View>
    </SafeAreaView>
  );
}

