149→    set({
150→      phase: 'game-over',
151→      gameOverData: data,
152→    }),
153→
154→  setOpponentConnected: (connected) => set({ opponentConnected: connected }),
155→
156→  isMyTurn: () => {
157→    const state = get();
158→    return state.currentTurn === state.myId;
159→  },
160→
161→  reset: () =>
162→    set({
163→      phase: 'waiting',
164→      hand: [],
