  1→import { useEffect, useCallback, useRef } from 'react';
  2→import { Socket } from 'socket.io-client';
  3→import { connectSocket, getSocket } from '../services/socket';
  4→import { useAppStore } from '../store/useAppStore';
  5→import { useGameStore } from '../store/useGameStore';
  6→import {
  7→  RoomCreatedPayload,
  8→  RoomJoinedPayload,
  9→  OpponentJoinedPayload,
 10→  GameStartPayload,
 11→  CardsDealtPayload,
 12→  CardPlayedPayload,
 13→  RoundEndPayload,
 14→  GameOverPayload,
 15→  ErrorPayload,
 16→} from '@basra/shared';
 17→
 18→export function useSocket() {
 19→  const socketRef = useRef<Socket | null>(null);
 20→
 21→  const { setPlayerId, setRoomCode, setConnected, playerId } = useAppStore();
 22→  const {
 23→    setMyId,
 24→    onGameStart,
 25→    onCardsDealt,
 26→    onCardPlayed,
 27→    onRoundEnd,
 28→    onGameOver,
 29→    setOpponentConnected,
 30→  } = useGameStore();
 31→
 32→  useEffect(() => {
 33→    const socket = connectSocket();
 34→    socketRef.current = socket;
 35→
 36→    const onConnect = () => setConnected(true);
 37→    const onDisconnect = () => setConnected(false);
 38→    const onConnectError = (err: Error) => console.warn('Socket connect error:', err.message);
 39→
 40→    const onRoomCreated = (data: RoomCreatedPayload) => {
 41→      setPlayerId(data.playerId);
 42→      setRoomCode(data.roomCode);
 43→      setMyId(data.playerId);
 44→    };
 45→
 46→    const onRoomJoined = (data: RoomJoinedPayload) => {
 47→      setPlayerId(data.playerId);
 48→      setRoomCode(data.roomCode);
 49→      setMyId(data.playerId);
 50→    };
 51→
 52→    const onGameStartHandler = (data: GameStartPayload) => {
 53→      const myId = useAppStore.getState().playerId;
 54→      if (myId) {
 55→        onGameStart(data, myId);
 56→      }
 57→    };
 58→
 59→    const onCardsDealtHandler = (data: CardsDealtPayload) => onCardsDealt(data);
 60→    const onCardPlayedHandler = (data: CardPlayedPayload) => onCardPlayed(data);
 61→    const onRoundEndHandler = (data: RoundEndPayload) => onRoundEnd(data);
 62→    const onGameOverHandler = (data: GameOverPayload) => onGameOver(data);
 63→    const onOpponentDisconnected = () => setOpponentConnected(false);
 64→    const onOpponentReconnected = () => setOpponentConnected(true);
 65→    const onError = (data: ErrorPayload) => console.warn('Server error:', data.message);
 66→
 67→    socket.on('connect', onConnect);
 68→    socket.on('disconnect', onDisconnect);
 69→    socket.on('connect_error', onConnectError);
 70→    socket.on('room-created', onRoomCreated);
 71→    socket.on('room-joined', onRoomJoined);
 72→    socket.on('game-start', onGameStartHandler);
 73→    socket.on('cards-dealt', onCardsDealtHandler);
 74→    socket.on('card-played', onCardPlayedHandler);
 75→    socket.on('round-end', onRoundEndHandler);
 76→    socket.on('game-over', onGameOverHandler);
 77→    socket.on('opponent-disconnected', onOpponentDisconnected);
 78→    socket.on('opponent-reconnected', onOpponentReconnected);
 79→    socket.on('error', onError);
 80→
 81→    return () => {
 82→      socket.off('connect', onConnect);
 83→      socket.off('disconnect', onDisconnect);
 84→      socket.off('connect_error', onConnectError);
 85→      socket.off('room-created', onRoomCreated);
 86→      socket.off('room-joined', onRoomJoined);
 87→      socket.off('game-start', onGameStartHandler);
 88→      socket.off('cards-dealt', onCardsDealtHandler);
 89→      socket.off('card-played', onCardPlayedHandler);
 90→      socket.off('round-end', onRoundEndHandler);
 91→      socket.off('game-over', onGameOverHandler);
 92→      socket.off('opponent-disconnected', onOpponentDisconnected);
 93→      socket.off('opponent-reconnected', onOpponentReconnected);
 94→      socket.off('error', onError);
 95→    };
 96→  }, []);
 97→
 98→  const createRoom = useCallback((nickname: string, targetScore?: number) => {
 99→    socketRef.current?.emit('create-room', { nickname, targetScore });
100→  }, []);
101→
102→  const joinRoom = useCallback((roomCode: string, nickname: string) => {
103→    socketRef.current?.emit('join-room', { roomCode, nickname });
104→  }, []);
105→
106→  const playerReady = useCallback(() => {
107→    socketRef.current?.emit('player-ready', {});
108→  }, []);
109→
110→  const playCard = useCallback((cardId: string) => {
111→    socketRef.current?.emit('play-card', { cardId });
112→  }, []);
113→
114→  const nextRound = useCallback(() => {
115→    socketRef.current?.emit('next-round', {});
116→  }, []);
117→
118→  const rematch = useCallback(() => {
119→    socketRef.current?.emit('rematch', {});
120→  }, []);
121→
122→  return {
123→    createRoom,
124→    joinRoom,
125→    playerReady,
126→    playCard,
127→    nextRound,
128→    rematch,
129→  };
130→}
