 1→import { io, Socket } from 'socket.io-client';
 2→
 3→const SERVER_URL = process.env.EXPO_PUBLIC_SERVER_URL || 'http://localhost:3000';
 4→
 5→let socket: Socket | null = null;
 6→
 7→export function getSocket(): Socket {
 8→  if (!socket) {
 9→    socket = io(SERVER_URL, {
10→      transports: ['websocket'],
11→      autoConnect: false,
12→    });
13→  }
14→  return socket;
15→}
16→
17→export function connectSocket(): Socket {
18→  const s = getSocket();
19→  if (!s.connected) {
20→    s.connect();
21→  }
22→  return s;
23→}
24→
25→export function disconnectSocket(): void {
26→  if (socket) {
27→    socket.disconnect();
28→    socket = null;
29→  }
30→}
