  4→
  5→function emitDeal(io: Server, room: Room): void {
  6→  const state = room.engine.getState();
  7→
  8→  for (const player of state.players) {
  9→    const sid = room.playerSockets.get(player.id);
 10→    if (!sid) continue;
 11→
 12→    const opponent = state.players.find(p => p.id !== player.id)!;
 13→
 14→    const dealtPayload: CardsDealtPayload = {
 15→      hand: player.hand,
 16→      deckRemaining: state.deckRemaining,
 17→      opponentCardCount: opponent.hand.length,
 18→    };
 19→    io.to(sid).emit('cards-dealt', dealtPayload);
 20→
 21→    if (state.currentTurn === player.id) {
 22→      io.to(sid).emit('your-turn', {});
 23→    }
