## 7. Specific Animation Implementations

### 7.1 Spring Configs

```typescript
// app/src/animation/springs.ts

export const SPRING_CONFIGS = {
  // Standard card movement (deal, fly to table)
  card: { damping: 12, stiffness: 100, mass: 0.8 },

  // Snappy (capture snap, quick settle)
  quick: { damping: 15, stiffness: 200, mass: 0.6 },

  // Bouncy (basra celebration, overshoot)
  bouncy: { damping: 6, stiffness: 150, mass: 1 },

  // Soft settle (return to hand after cancelled drag)
  settle: { damping: 14, stiffness: 80, mass: 1 },

  // Heavy (pile drop)
  heavy: { damping: 18, stiffness: 120, mass: 1.2 },
} as const;

export const TIMING = {
  dealStagger: 120,       // ms between each card dealt
  captureConverge: 200,   // ms for captured cards to converge
  captureToFile: 350,     // ms for capture group to fly to pile
  flipDuration: 200,      // ms for card flip
  shuffleWiggle: 80,      // ms per wiggle cycle
  shuffleCycles: 5,       // number of wiggles
  preDealPause: 300,      // pause after shuffle before dealing
  roundEndDelay: 800,     // pause before table cleanup
  basraToastDuration: 1800,
} as const;
```

### 7.2 Game Start Sequence

```typescript
// app/src/animation/animations.ts

export async function gameStartSequence(
  event: GameStartEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  // Phase 1: Create deck visual (stack of cards at deck position)
  // Deck is represented by 3-4 stacked card backs for visual depth
  // Position all at layout.deck

  // Phase 2: Shuffle animation
  await shuffleAnimation(entities, layout);

  // Phase 3: Deal 4 to opponent (staggered, face-down, fly from deck to opponent positions)
  const opponentPositions = layout.opponentPositions(event.opponentCardCount);
  for (let i = 0; i < event.opponentCardCount; i++) {
    const entity = createOpponentCardEntity(i, layout.deck);
    entities.set(entity.id, entity);

    // Fly from deck to opponent position
    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, opponentPositions[i].pos, opponentPositions[i].rotation);
  }

  // Phase 4: Deal 4 to table (staggered, face-up, fly from deck to table positions)
  const tablePositions = layout.tablePositions(event.tableCards.length);
  for (let i = 0; i < event.tableCards.length; i++) {
    const entity = createTableCardEntity(event.tableCards[i], layout.deck);
    entities.set(entity.id, entity);

    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, tablePositions[i], 0);
    // Flip to face-up partway through the flight
    entity.faceUp = true; // React re-render triggers face change
  }

  // Phase 5: Deal 4 to my hand (staggered, fly from deck to hand positions)
  const handPositions = layout.handPositions(event.hand.length);
  for (let i = 0; i < event.hand.length; i++) {
    const entity = createHandCardEntity(event.hand[i], layout.deck);
    entities.set(entity.id, entity);

    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, handPositions[i].pos, handPositions[i].rotation);
    entity.faceUp = true;
  }

  // All cards settled -- animation complete
}
```

### 7.3 My Card Played Sequence

When I drag and release a card over the table, the card is already visually near the table. The animation queue handles the rest.

```typescript
export async function myPlaySequence(
  event: MyPlayEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  const playedEntity = entities.get(event.card.id)!;

  // Step 1: Animate card to table center (it's already near from drag)
  const tableTarget = layout.tableCenter;
  await animatePosition(playedEntity, tableTarget, SPRING_CONFIGS.quick);
  playedEntity.zone = 'table';

  // Step 2: Check for captures
  if (event.capturedCards.length > 0) {
    // Step 2a: Brief pause for dramatic effect
    await delay(150);

    // Step 2b: All captured cards + played card converge to center
    const capturedEntities = event.capturedCards.map(c => entities.get(c.id)!);
    const allCapturing = [playedEntity, ...capturedEntities];

    await Promise.all(
      allCapturing.map(e => animatePosition(e, tableTarget, SPRING_CONFIGS.quick))
    );

    // Step 2c: Scale pulse on convergence
    await Promise.all(
      allCapturing.map(e => animateSpring(e.scale, 1.15, SPRING_CONFIGS.bouncy))
    );

    // Step 2d: Fly entire group to my pile
    await Promise.all(
      allCapturing.map((e, i) =>
        delay(i * 30).then(() => {
          e.zIndex.value = 500 + i;
          return Promise.all([
            animatePosition(e, layout.myPile, SPRING_CONFIGS.card),
            animateSpring(e.scale, 0.5, SPRING_CONFIGS.card),
            animateSpring(e.opacity, 0, { duration: 400 }),
          ]);
        })
      )
    );

    // Step 2e: Remove captured entities, update pile count visual
    for (const e of allCapturing) {
      entities.delete(e.id);
    }

    // Step 2f: Basra celebration
    if (event.isBasra || event.isJackBasra) {
      // Trigger basra toast + haptic
      // (handled via a callback or by setting a reactive state)
    }
  } else {
    // No capture -- card joins the table
    // Reposition all table cards to new layout positions
    const newTablePositions = layout.tablePositions(event.tableAfter.length);
    const tableCards = event.tableAfter.map(c => entities.get(c.id)!);

    await Promise.all(
      tableCards.map((e, i) =>
        animatePosition(e, newTablePositions[i], SPRING_CONFIGS.settle)
      )
    );
  }

  // Step 3: Re-fan remaining hand cards
  const remainingHand = /* hand entities minus played card */;
  const newHandPositions = layout.handPositions(remainingHand.length);
  await Promise.all(
    remainingHand.map((e, i) =>
      Promise.all([
        animatePosition(e, newHandPositions[i].pos, SPRING_CONFIGS.settle),
        animateSpring(e.rotation, newHandPositions[i].rotation, SPRING_CONFIGS.settle),
      ])
    )
  );
}
```

