### 7.6 Shuffle Animation

```typescript
export async function shuffleAnimation(
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  // Get deck visual entities (the 3-4 stacked card backs at deck position)
  const deckEntities = /* deck visual entities */;

  for (let cycle = 0; cycle < TIMING.shuffleCycles; cycle++) {
    for (const entity of deckEntities) {
      entity.rotation.value = withTiming(
        (cycle % 2 === 0 ? 1 : -1) * 0.05,
        { duration: TIMING.shuffleWiggle }
      );
      entity.x.value = withTiming(
        layout.deck.x + (cycle % 2 === 0 ? 4 : -4),
        { duration: TIMING.shuffleWiggle }
      );
    }
    await delay(TIMING.shuffleWiggle);
  }

  // Settle back to deck position
  for (const entity of deckEntities) {
    entity.rotation.value = withSpring(0, SPRING_CONFIGS.quick);
    entity.x.value = withSpring(layout.deck.x, SPRING_CONFIGS.quick);
  }

  await delay(TIMING.preDealPause);
}
```

### 7.7 Round End Sequence

```typescript
export async function roundEndSequence(
  event: RoundEndEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  await delay(TIMING.roundEndDelay);

  // Remaining table cards fly to last capturer's pile
  const tableEntities = [...entities.values()].filter(e => e.zone === 'table');
  const targetPile = event.lastCapturerId === /* myId */ ? layout.myPile : layout.opponentPile;

  await Promise.all(
    tableEntities.map((e, i) =>
      delay(i * 50).then(() =>
        Promise.all([
          animatePosition(e, targetPile, SPRING_CONFIGS.card),
          animateSpring(e.scale, 0.5, SPRING_CONFIGS.card),
          animateTiming(e.opacity, 0, { duration: 400 }),
        ])
      )
    )
  );

  // Clean up all entities
  for (const e of tableEntities) {
    entities.delete(e.id);
  }

  // Brief pause before navigation
  await delay(600);

  // Trigger navigation to score screen
}
