## 9. Captured Pile Component

```typescript
// app/src/components/CapturedPile.tsx

import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import Animated, { useAnimatedStyle, withSpring } from 'react-native-reanimated';
import { cardDimensions, colors } from '../theme';

interface CapturedPileProps {
  count: number;
  basraCount: number;
  position: { x: number; y: number };
  isOpponent?: boolean;
}

export const CapturedPile = React.memo(function CapturedPile({
  count,
  basraCount,
  position,
  isOpponent,
}: CapturedPileProps) {
  const scale = isOpponent ? 0.55 : 0.7;
  const w = cardDimensions.width * scale;
  const h = cardDimensions.height * scale;

  // Visual stack: render min(count, 5) card backs stacked with offsets
  const stackCount = Math.min(count, 5);

  return (
    <View style={[styles.container, { left: position.x, top: position.y }]}>
      {Array.from({ length: stackCount }).map((_, i) => (
        <View
          key={i}
          style={[
            styles.stackedCard,
            {
              width: w,
              height: h,
              top: -i * 2,    // stack grows upward
              left: i * 0.5,  // slight horizontal offset
            },
          ]}
        />
      ))}
      <Text style={styles.countText}>{count}</Text>
      {basraCount > 0 && (
        <Text style={styles.basraText}>{basraCount}x B</Text>
      )}
    </View>
  );
});
