## 4. The Flat Card Layer: Position Calculation

### 4.1 `useGameLayout` Hook

This hook takes board dimensions from `GameBoard`'s `onLayout` and computes zone positions.

```typescript
// app/src/animation/useGameLayout.ts

import { useMemo } from 'react';
import { cardDimensions } from '../theme';

const CARD_W = cardDimensions.width;   // 60
const CARD_H = cardDimensions.height;  // 84
const SMALL_CARD_W = CARD_W * 0.7;    // 42
const SMALL_CARD_H = CARD_H * 0.7;    // 58.8

export function useGameLayout(boardWidth: number, boardHeight: number): ZoneLayout {
  return useMemo(() => {
    const cx = boardWidth / 2;

    // Vertical zones (approximate):
    // 0-15%:     opponent hand area
    // 15-20%:    opponent pile
    // 20-65%:    table area
    // 65-70%:    deck + my pile
    // 75-100%:   my hand area

    const opponentY = boardHeight * 0.06;
    const tableTopY = boardHeight * 0.22;
    const tableCenterY = boardHeight * 0.40;
    const deckY = boardHeight * 0.62;
    const handY = boardHeight * 0.82;

    const deck = { x: cx - CARD_W / 2, y: deckY };
    const tableCenter = { x: cx, y: tableCenterY };
    const myPile = { x: boardWidth - CARD_W - 16, y: boardHeight * 0.68 };
    const opponentPile = { x: boardWidth - SMALL_CARD_W - 16, y: boardHeight * 0.08 };

    // Hand positions: fan arc centered at bottom
    const handPositions = (count: number) => {
      if (count === 0) return [];
      const spread = Math.min(50, 200 / count); // px between cards, max overlap
      const totalWidth = (count - 1) * spread + CARD_W;
      const startX = cx - totalWidth / 2;
      const arcHeight = 8; // slight arc

      return Array.from({ length: count }, (_, i) => {
        const t = count === 1 ? 0.5 : i / (count - 1);
        const arcY = -arcHeight * Math.sin(t * Math.PI); // parabolic arc
        const rot = (t - 0.5) * 0.08; // slight fan rotation, +/-0.04 rad
        return {
          pos: { x: startX + i * spread, y: handY + arcY },
          rotation: rot,
        };
      });
    };

    // Table positions: scattered grid
    const tablePositions = (count: number) => {
      if (count === 0) return [];
      const cols = Math.min(count, 5);
      const gap = SMALL_CARD_W + 8;
      const totalW = (cols - 1) * gap + SMALL_CARD_W;
      const startX = cx - totalW / 2;

      return Array.from({ length: count }, (_, i) => {
        const col = i % cols;
        const row = Math.floor(i / cols);
        // Add slight randomness for scatter feel
        const jitterX = ((i * 7) % 11 - 5) * 1.5;
        const jitterY = ((i * 13) % 11 - 5) * 1.5;
        return {
          x: startX + col * gap + jitterX,
          y: tableTopY + row * (SMALL_CARD_H + 6) + jitterY,
        };
      });
    };

    // Opponent positions: similar to hand but smaller and inverted
    const opponentPositions = (count: number) => {
      if (count === 0) return [];
      const spread = Math.min(35, 140 / count);
      const totalWidth = (count - 1) * spread + SMALL_CARD_W;
      const startX = cx - totalWidth / 2;

      return Array.from({ length: count }, (_, i) => {
        const t = count === 1 ? 0.5 : i / (count - 1);
        const rot = (t - 0.5) * 0.06;
        return {
          pos: { x: startX + i * spread, y: opponentY },
          rotation: rot,
        };
      });
    };

    return {
      boardWidth, boardHeight,
      deck, tableCenter, myPile, opponentPile,
      handPositions, tablePositions, opponentPositions,
    };
  }, [boardWidth, boardHeight]);
}
```

### 4.2 `AnimatedCard` Component

Each `AnimatedCard` reads shared values via `useAnimatedStyle` and optionally attaches a `Gesture.Pan()` for hand cards.

```typescript
// app/src/components/AnimatedCard.tsx

import React from 'react';
import { StyleSheet, Text, View } from 'react-native';
import Animated, { useAnimatedStyle } from 'react-native-reanimated';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';
import { CardEntity } from '../animation/types';
import { getSuitSymbol, getSuitColor, getDisplayRank } from '../utils/cardImages';
import { cardDimensions, colors } from '../theme';

interface AnimatedCardProps {
  entity: CardEntity;
  gesture?: ReturnType<typeof Gesture.Pan>;  // only for hand cards
  small?: boolean;
}

export const AnimatedCard = React.memo(function AnimatedCard({ entity, gesture, small }: AnimatedCardProps) {
  const w = small ? cardDimensions.width * 0.7 : cardDimensions.width;
  const h = small ? cardDimensions.height * 0.7 : cardDimensions.height;

  const animatedStyle = useAnimatedStyle(() => ({
    position: 'absolute',
    left: 0,
    top: 0,
    width: w,
    height: h,
    transform: [
      { translateX: entity.x.value + entity.dragOffsetX.value },
      { translateY: entity.y.value + entity.dragOffsetY.value },
      { rotate: `${entity.rotation.value}rad` },
      { scale: entity.scale.value },
    ],
    opacity: entity.opacity.value,
    zIndex: entity.zIndex.value,
  }));

  const cardContent = entity.faceUp && entity.card ? (
    <FaceUpContent card={entity.card} small={small} />
  ) : (
    <FaceDownContent />
  );

  const cardView = (
    <Animated.View style={[styles.card, small && styles.small, animatedStyle]}>
      {cardContent}
    </Animated.View>
  );

  if (gesture) {
    return <GestureDetector gesture={gesture}>{cardView}</GestureDetector>;
  }

  return cardView;
});
```

The key insight: `useAnimatedStyle` with shared values means the card re-renders only when React props change (entity reference, gesture). All position/transform updates happen on the UI thread via shared values -- zero React re-renders during animations.

