## 6. Animation Queue

### 6.1 Core Queue Design

The animation queue is the most architecturally significant piece. It sits between server events and the visual card layer.

```typescript
// app/src/animation/useAnimationQueue.ts

import { useRef, useCallback } from 'react';
import { AnimationEvent, QueuedAnimation, CardEntity, ZoneLayout } from './types';
import * as animations from './animations';

export function useAnimationQueue(
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
  commitToStore: (event: AnimationEvent) => void,
) {
  const queueRef = useRef<QueuedAnimation[]>([]);
  const isProcessingRef = useRef(false);

  const enqueue = useCallback((event: AnimationEvent) => {
    queueRef.current.push({ event, timestamp: Date.now() });
    processNext();
  }, []);

  const processNext = useCallback(async () => {
    if (isProcessingRef.current) return;
    if (queueRef.current.length === 0) return;

    isProcessingRef.current = true;
    const { event } = queueRef.current.shift()!;

    try {
      await runAnimation(event);
      commitToStore(event);
    } finally {
      isProcessingRef.current = false;
      processNext(); // process next in queue
    }
  }, []);

  const runAnimation = async (event: AnimationEvent): Promise<void> => {
    switch (event.type) {
      case 'GAME_START':
        await animations.gameStartSequence(event, entities, layout);
        break;
      case 'CARD_PLAYED_BY_ME':
        await animations.myPlaySequence(event, entities, layout);
        break;
      case 'CARD_PLAYED_BY_OPPONENT':
        await animations.opponentPlaySequence(event, entities, layout);
        break;
      case 'CARDS_DEALT':
        await animations.dealSequence(event, entities, layout);
        break;
      case 'ROUND_END':
        await animations.roundEndSequence(event, entities, layout);
        break;
      case 'GAME_OVER':
        await animations.gameOverSequence(event, entities, layout);
        break;
    }
  };

  return { enqueue };
}
```

### 6.2 Promise-Based Animation Completion

Reanimated 3 animations are imperative and don't natively return promises. We use the `withTiming`/`withSpring` callback to resolve promises.

```typescript
// app/src/animation/utils.ts

import { SharedValue, withSpring, withTiming, withDelay } from 'react-native-reanimated';

/**
 * Animate a shared value and return a Promise that resolves when the animation completes.
 * Must be called from JS thread (use runOnJS if needed from worklet).
 */
export function animateSpring(
  sv: SharedValue<number>,
  toValue: number,
  config: object,
): Promise<void> {
  return new Promise((resolve) => {
    sv.value = withSpring(toValue, config, (finished) => {
      if (finished) {
        runOnJS(resolve)();
      }
    });
  });
}

export function animateTiming(
  sv: SharedValue<number>,
  toValue: number,
  config: object,
): Promise<void> {
  return new Promise((resolve) => {
    sv.value = withTiming(toValue, config, (finished) => {
      if (finished) {
        runOnJS(resolve)();
      }
    });
  });
}

/** Animate position (x,y) simultaneously, resolving when both complete */
export function animatePosition(
  entity: CardEntity,
  target: { x: number; y: number },
  config: object,
): Promise<void> {
  return Promise.all([
    animateSpring(entity.x, target.x, config),
    animateSpring(entity.y, target.y, config),
  ]).then(() => {});
}

export function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}
```

