### 7.2 Game Start Sequence

```typescript
// app/src/animation/animations.ts

export async function gameStartSequence(
  event: GameStartEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  // Phase 1: Create deck visual (stack of cards at deck position)
  // Deck is represented by 3-4 stacked card backs for visual depth
  // Position all at layout.deck

  // Phase 2: Shuffle animation
  await shuffleAnimation(entities, layout);

  // Phase 3: Deal 4 to opponent (staggered, face-down, fly from deck to opponent positions)
  const opponentPositions = layout.opponentPositions(event.opponentCardCount);
  for (let i = 0; i < event.opponentCardCount; i++) {
    const entity = createOpponentCardEntity(i, layout.deck);
    entities.set(entity.id, entity);

    // Fly from deck to opponent position
    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, opponentPositions[i].pos, opponentPositions[i].rotation);
  }

  // Phase 4: Deal 4 to table (staggered, face-up, fly from deck to table positions)
  const tablePositions = layout.tablePositions(event.tableCards.length);
  for (let i = 0; i < event.tableCards.length; i++) {
    const entity = createTableCardEntity(event.tableCards[i], layout.deck);
    entities.set(entity.id, entity);

    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, tablePositions[i], 0);
    // Flip to face-up partway through the flight
    entity.faceUp = true; // React re-render triggers face change
  }

  // Phase 5: Deal 4 to my hand (staggered, fly from deck to hand positions)
  const handPositions = layout.handPositions(event.hand.length);
  for (let i = 0; i < event.hand.length; i++) {
    const entity = createHandCardEntity(event.hand[i], layout.deck);
    entities.set(entity.id, entity);

    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, handPositions[i].pos, handPositions[i].rotation);
    entity.faceUp = true;
  }

  // All cards settled -- animation complete
}
