### 7.3 My Card Played Sequence

When I drag and release a card over the table, the card is already visually near the table. The animation queue handles the rest.

```typescript
export async function myPlaySequence(
  event: MyPlayEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  const playedEntity = entities.get(event.card.id)!;

  // Step 1: Animate card to table center (it's already near from drag)
  const tableTarget = layout.tableCenter;
  await animatePosition(playedEntity, tableTarget, SPRING_CONFIGS.quick);
  playedEntity.zone = 'table';

  // Step 2: Check for captures
  if (event.capturedCards.length > 0) {
    // Step 2a: Brief pause for dramatic effect
    await delay(150);

    // Step 2b: All captured cards + played card converge to center
    const capturedEntities = event.capturedCards.map(c => entities.get(c.id)!);
    const allCapturing = [playedEntity, ...capturedEntities];

    await Promise.all(
      allCapturing.map(e => animatePosition(e, tableTarget, SPRING_CONFIGS.quick))
    );

    // Step 2c: Scale pulse on convergence
    await Promise.all(
      allCapturing.map(e => animateSpring(e.scale, 1.15, SPRING_CONFIGS.bouncy))
    );

    // Step 2d: Fly entire group to my pile
    await Promise.all(
      allCapturing.map((e, i) =>
        delay(i * 30).then(() => {
          e.zIndex.value = 500 + i;
          return Promise.all([
            animatePosition(e, layout.myPile, SPRING_CONFIGS.card),
            animateSpring(e.scale, 0.5, SPRING_CONFIGS.card),
            animateSpring(e.opacity, 0, { duration: 400 }),
          ]);
        })
      )
    );

    // Step 2e: Remove captured entities, update pile count visual
    for (const e of allCapturing) {
      entities.delete(e.id);
    }

    // Step 2f: Basra celebration
    if (event.isBasra || event.isJackBasra) {
      // Trigger basra toast + haptic
      // (handled via a callback or by setting a reactive state)
    }
  } else {
    // No capture -- card joins the table
    // Reposition all table cards to new layout positions
    const newTablePositions = layout.tablePositions(event.tableAfter.length);
    const tableCards = event.tableAfter.map(c => entities.get(c.id)!);

    await Promise.all(
      tableCards.map((e, i) =>
        animatePosition(e, newTablePositions[i], SPRING_CONFIGS.settle)
      )
    );
  }

  // Step 3: Re-fan remaining hand cards
  const remainingHand = /* hand entities minus played card */;
  const newHandPositions = layout.handPositions(remainingHand.length);
  await Promise.all(
    remainingHand.map((e, i) =>
      Promise.all([
        animatePosition(e, newHandPositions[i].pos, SPRING_CONFIGS.settle),
        animateSpring(e.rotation, newHandPositions[i].rotation, SPRING_CONFIGS.settle),
      ])
    )
  );
}
