### 7.5 Deal Sequence (mid-game re-deal)

```typescript
export async function dealSequence(
  event: CardsDealtEvent,
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  // Step 1: Deck shuffle wiggle
  await shuffleAnimation(entities, layout);

  // Step 2: Deal to opponent (face-down cards fly from deck)
  for (let i = 0; i < event.opponentCardCount; i++) {
    const entity = createOpponentCardEntity(i, layout.deck);
    entities.set(entity.id, entity);
    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, layout.opponentPositions(event.opponentCardCount)[i].pos, ...);
  }

  // Step 3: Deal to my hand (face-up fly from deck)
  for (let i = 0; i < event.hand.length; i++) {
    const entity = createHandCardEntity(event.hand[i], layout.deck);
    entities.set(entity.id, entity);
    await delay(TIMING.dealStagger);
    flyCardToPosition(entity, layout.handPositions(event.hand.length)[i].pos, ...);
    entity.faceUp = true;
  }
}
