### 7.6 Shuffle Animation

```typescript
export async function shuffleAnimation(
  entities: Map<string, CardEntity>,
  layout: ZoneLayout,
): Promise<void> {
  // Get deck visual entities (the 3-4 stacked card backs at deck position)
  const deckEntities = /* deck visual entities */;

  for (let cycle = 0; cycle < TIMING.shuffleCycles; cycle++) {
    for (const entity of deckEntities) {
      entity.rotation.value = withTiming(
        (cycle % 2 === 0 ? 1 : -1) * 0.05,
        { duration: TIMING.shuffleWiggle }
      );
      entity.x.value = withTiming(
        layout.deck.x + (cycle % 2 === 0 ? 4 : -4),
        { duration: TIMING.shuffleWiggle }
      );
    }
    await delay(TIMING.shuffleWiggle);
  }

  // Settle back to deck position
  for (const entity of deckEntities) {
    entity.rotation.value = withSpring(0, SPRING_CONFIGS.quick);
    entity.x.value = withSpring(layout.deck.x, SPRING_CONFIGS.quick);
  }

  await delay(TIMING.preDealPause);
}
```

