## 8. CardEntity Pool Management (`useCardEntities`)

```typescript
// app/src/animation/useCardEntities.ts

import { useRef, useCallback } from 'react';
import { useSharedValue } from 'react-native-reanimated';
import { CardEntity, CardZone, Point } from './types';
import { Card } from '@basra/shared';

export function useCardEntities() {
  const entitiesRef = useRef(new Map<string, CardEntity>());
  const [, forceRender] = useState(0); // trigger re-render when entities change

  const createEntity = useCallback((
    id: string,
    card: Card | null,
    faceUp: boolean,
    zone: CardZone,
    initialPos: Point,
  ): CardEntity => {
    // IMPORTANT: useSharedValue can only be called at component level.
    // For dynamic entity creation, we must use makeMutable (Reanimated 3 API)
    // or pre-allocate a pool.
    //
    // Alternative approach: Use a fixed-size entity pool (max ~20 cards visible)
    // and recycle entities.

    const entity: CardEntity = {
      id,
      card,
      faceUp,
      zone,
      x: makeMutable(initialPos.x),
      y: makeMutable(initialPos.y),
      rotation: makeMutable(0),
      scale: makeMutable(1),
      opacity: makeMutable(faceUp ? 1 : 1),
      zIndex: makeMutable(0),
      isDragging: makeMutable(0),
      dragOffsetX: makeMutable(0),
      dragOffsetY: makeMutable(0),
    };

    entitiesRef.current.set(id, entity);
    forceRender(n => n + 1);
    return entity;
  }, []);

  const removeEntity = useCallback((id: string) => {
    entitiesRef.current.delete(id);
    forceRender(n => n + 1);
  }, []);

  const getEntity = useCallback((id: string) => entitiesRef.current.get(id), []);

  const getAllEntities = useCallback(() => [...entitiesRef.current.values()], []);

  return { createEntity, removeEntity, getEntity, getAllEntities, entities: entitiesRef };
}
```

**Critical note on `makeMutable` vs `useSharedValue`**: Since card entities are created dynamically (not at component mount), we cannot use `useSharedValue` (which is a React hook). Reanimated 3 provides `makeMutable` for creating shared values outside of hooks. This is the correct API for our dynamic card pool.

```typescript
import { makeMutable } from 'react-native-reanimated';
```

